// OpenCL kernel translated from OpenMP parallel region in XSbench simulation

__kernel void xsbench_simulation_kernel(
    __global float *grid,      // 2D grid stored in 1D array (row-major)
    const int grid_size_x,
    const int grid_size_y,
    const int num_particles,
    __global float *results   // output buffer for results per particle
) {
    int gid = get_global_id(0);
    if (gid >= num_particles) return;

    // Example simulation of particle transport in grid
    // Each thread handles one particle

    // Initialize particle position (for example, random or deterministic)
    // For demo, position depends on gid
    int x = gid % grid_size_x;
    int y = gid % grid_size_y;

    float accum = 0.0f;

    // Simulate particle moving through grid cells
    for (int step = 0; step < 100; step++) {
        // Compute index in 1D grid array
        int idx = y * grid_size_x + x;

        // Access grid data and accumulate some value
        accum += grid[idx];

        // Update particle position (simple example: move diagonally)
        x = (x + 1) % grid_size_x;
        y = (y + 1) % grid_size_y;
    }

    // Store result for this particle
    results[gid] = accum;
}
